<template><div><h1>注销记录</h1><el-card shadow="never"><el-table :data="rows" v-loading="loading" border><el-table-column prop="cancellationNo" label="注销编号"/><el-table-column prop="cancelObjectType" label="对象"/><el-table-column prop="personName" label="人员"/><el-table-column prop="identityNo" label="身份证号"/><el-table-column prop="householdNo" label="户号"/><el-table-column prop="cancelReasonCode" label="原因"/><el-table-column prop="businessStatus" label="状态"/><el-table-column prop="executedAt" label="执行时间"/></el-table></el-card></div></template><script setup>import{onMounted,ref}from'vue';import{listCancellations}from'../../api/cancellations';const rows=ref([]),loading=ref(false);async function load(){loading.value=true;try{rows.value=(await listCancellations({size:50})).content||[]}finally{loading.value=false}}onMounted(load);</script>
